// Analytic caustics — JSON-editable (§5.6 open-family kernel: edit the wave
// table to reshape the water). Four directional plane waves h = Σ A·sin(k·x+ωt)
// have closed-form Hessians, so ray-bundle focusing I = shine/|det(I+depth·H)|
// is computed exactly per pixel — no finite differences (f16 texture
// derivatives drown in quantization noise; that approach was tried and
// abandoned 2026-07-16), no particles, perfectly smooth.
struct P { time: f32, depth: f32, scale: f32, speed: f32, shine: f32, };
@group(0) @binding(0) var<uniform> u: P;
@group(0) @binding(1) var output_tex: texture_storage_2d<rgba16float, write>;

@compute @workgroup_size(16, 16)
fn cs_main(@builtin(global_invocation_id) id: vec3<u32>) {
    let dims = vec2<f32>(textureDimensions(output_tex));
    if id.x >= u32(dims.x) || id.y >= u32(dims.y) { return; }
    let uv = (vec2<f32>(id.xy) + 0.5) / dims;

    // wave table: direction (unnormalised), relative frequency, relative speed, amplitude
    var dir = array<vec2<f32>, 5>(
        vec2<f32>( 1.0,  0.42), vec2<f32>(-0.68, 0.91),
        vec2<f32>( 0.57, -0.83), vec2<f32>( 0.31, 1.08),
        vec2<f32>( 1.04,  0.18));
    var frq = array<f32, 5>(2.1, 3.1, 4.7, 6.7, 8.9);
    var spd = array<f32, 5>(0.7, -1.13, 1.61, -2.23, 2.9);
    var amp = array<f32, 5>(1.0, 0.82, 0.6, 0.42, 0.3);
    var pha = array<f32, 5>(0.0, 1.7, 3.9, 5.1, 0.9);

    var hxx = 0.0; var hyy = 0.0; var hxy = 0.0;
    for (var i = 0; i < 5; i = i + 1) {
        let k = dir[i] * frq[i] * u.scale;
        let phase = dot(k, uv) + u.time * u.speed * spd[i] + pha[i];
        let s = sin(phase) * amp[i];
        hxx = hxx - k.x * k.x * s;
        hyy = hyy - k.y * k.y * s;
        hxy = hxy - k.x * k.y * s;
    }
    let a = 1.0 + u.depth * hxx;
    let b = 1.0 + u.depth * hyy;
    let c = u.depth * hxy;
    let det = abs(a * b - c * c);
    let light = u.shine / (det + 0.02);
    textureStore(output_tex, vec2<i32>(id.xy), vec4<f32>(light, light, light, 1.0));
}
